import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.DNt_9s2P.js";const m=JSON.parse('{"title":"機能一覧","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features.md","filePath":"guide/features.md"}'),i={name:"guide/features.md"};function l(h,t,o,n,u,s){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="機能一覧" tabindex="-1">機能一覧 <a class="header-anchor" href="#機能一覧" aria-label="Permalink to &quot;機能一覧&quot;">​</a></h1><p>Selah は関西学院大学の学生生活に必要な情報を 1 つのアプリに統合します。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>説明</th><th>データソース</th></tr></thead><tbody><tr><td><a href="/KWIC/guide/home.html">ホーム</a></td><td>ダッシュボード画面</td><td>KWIC + Luna + Open-Meteo</td></tr><tr><td><a href="/KWIC/guide/timetable.html">時間割</a></td><td>週間グリッド表示 + カレンダー同期</td><td>KWIC + Luna</td></tr><tr><td><a href="/KWIC/guide/todo.html">TODO / 課題</a></td><td>課題管理 + レポート提出</td><td>Luna</td></tr><tr><td><a href="/KWIC/guide/mail.html">メール</a></td><td>大学メール閲覧</td><td>Microsoft 365</td></tr><tr><td><a href="/KWIC/guide/grades.html">成績照会</a></td><td>単位取得状況</td><td>KWIC</td></tr><tr><td>履修登録</td><td>登録科目一覧 + 単位サマリー</td><td>KWIC</td></tr><tr><td><a href="/KWIC/guide/syllabus.html">シラバス検索</a></td><td>多条件検索 + お気に入り</td><td>KWIC</td></tr><tr><td>お知らせ</td><td>KWIC + Luna の通知を統合表示</td><td>KWIC + Luna</td></tr><tr><td>変更情報</td><td>休講・補講・教室変更</td><td>KWIC</td></tr><tr><td><a href="/KWIC/guide/ai.html">AI 機能</a></td><td>履修分析・学習計画・サマリー</td><td>OpenAI / Gemini</td></tr></tbody></table><h2 id="プラットフォーム統合" tabindex="-1">プラットフォーム統合 <a class="header-anchor" href="#プラットフォーム統合" aria-label="Permalink to &quot;プラットフォーム統合&quot;">​</a></h2><h3 id="トレイステータス" tabindex="-1">トレイステータス <a class="header-anchor" href="#トレイステータス" aria-label="Permalink to &quot;トレイステータス&quot;">​</a></h3><p>メニューバー（macOS）/ タスクトレイ（Windows）に以下の情報をサイクル表示します：</p><ul><li>現在の授業</li><li>次の授業</li><li>未提出の課題数</li></ul><p>クリックでポップアップに詳細を表示。</p><h3 id="ネイティブ通知" tabindex="-1">ネイティブ通知 <a class="header-anchor" href="#ネイティブ通知" aria-label="Permalink to &quot;ネイティブ通知&quot;">​</a></h3><p>新着のお知らせや課題をデスクトップ通知でリアルタイムに通知します。</p><ul><li>macOS: 通知センター連携</li><li>Windows: トースト通知</li></ul><h3 id="バックグラウンドポーリング" tabindex="-1">バックグラウンドポーリング <a class="header-anchor" href="#バックグラウンドポーリング" aria-label="Permalink to &quot;バックグラウンドポーリング&quot;">​</a></h3><p>時間割・お知らせ・TODO・メールなどを定期的に自動取得し、キャッシュを更新します。</p><h3 id="オフラインフォールバック" tabindex="-1">オフラインフォールバック <a class="header-anchor" href="#オフラインフォールバック" aria-label="Permalink to &quot;オフラインフォールバック&quot;">​</a></h3><p>SQLite (WAL モード) によるローカルデータベースにすべてのデータをキャッシュ。ネットワークに接続できない場合でもキャッシュデータで閲覧可能です。</p>',16)])])}const f=a(i,[["render",l]]);export{m as __pageData,f as default};
